INSERT INTO users (id, name) VALUES (1, 'Тест');
INSERT INTO posts (user_id, title, text) VALUES
(1, 'Утренняя рыбалка на озере', 'Сегодня встал в четыре утра и поехал на озеро. Тишина невероятная, туман над водой. Поймал трёх карасей и одного леща. Лещ попался крупный, грамм на восемьсот. Такое утро стоит того, чтобы не выспаться.'),
(1, 'Почему коты спят по 16 часов', 'Мой кот Барсик спит буквально везде — на диване, на столе, в коробке из-под обуви. Прочитал, что коты спят до 16 часов в сутки. Это связано с их хищной природой — они экономят энергию между охотами. Хотя Барсик охотится максимум на мух.'),
(1, 'Погода в марте — сюрприз за сюрпризом', 'Утром было солнце, к обеду повалил снег, а вечером опять распогодилось. Март как обычно не может определиться. Уже хочется весны по-настоящему.'),
(1, 'Пробежка в парке', 'Начал бегать по утрам. Пока получается два километра, но планирую дойти до пяти. Парк рядом с домом отлично подходит — дорожки ровные, воздух свежий. Главное не забросить.'),
(1, 'Выходные на даче', 'Провели выходные на даче. Жарили шашлыки, играли в бадминтон, вечером сидели у костра. Дети были в восторге. Надо чаще так выбираться.'),
(1, 'Новый спиннинг', 'Купил наконец нормальный спиннинг. Shimano, карбоновый, лёгкий. Прошлый был тяжёлый и неудобный. В выходные поеду тестировать на речку. Надеюсь щука оценит.'),
(1, 'Кот и огурец', 'Видели эти видео, где коты пугаются огурцов? Решил проверить на своём. Барсик посмотрел на огурец, понюхал и ушёл. Никакой реакции. Бесстрашный кот.'),
(1, 'Дождь третий день подряд', 'Дождь не прекращается уже три дня. На улице серо и сыро. Настроение соответствующее. Зато грибы потом будут — надо готовить корзинки.'),
(1, 'Футбол с друзьями', 'Собрались поиграть в футбол после работы. Пять на пять. Проиграли 3:7, но было весело. Ноги потом болели два дня, надо чаще заниматься спортом.'),
(1, 'Отпуск у моря', 'Две недели у моря — лучший отдых. Каждый день купались, загорали, ели свежие фрукты. Вернулись загорелые и отдохнувшие. Уже скучаю по шуму волн.'),
(1, 'Зимняя рыбалка', 'Первый раз попробовал зимнюю рыбалку. Сидишь на льду, мёрзнешь, ждёшь поклёвки. Поймал пять окуней. Ощущения непередаваемые, но термос с чаем — вещь обязательная.'),
(1, 'Кот на клавиатуре', 'Работаю из дома, а Барсик постоянно ложится на клавиатуру. Написал какую-то абракадабру в рабочий чат. Коллеги спросили, всё ли у меня в порядке.'),
(1, 'Аномальная жара', 'Плюс тридцать пять в тени. Асфальт плавится. Спасает только кондиционер и мороженое. Даже кот лежит на полу и не двигается.'),
(1, 'Утренняя зарядка', 'Стал делать зарядку каждое утро. Пятнадцать минут — отжимания, приседания, планка. Чувствую себя бодрее в течение дня. Привычка формируется за 21 день, осталось 18.'),
(1, 'Пикник в лесу', 'Взяли палатку и уехали на выходные в лес. Речка рядом, птицы поют, костёр потрескивает. Полная перезагрузка от городской суеты.'),
(1, 'Судак на джиг', 'Ездил за судаком. Ловил на джиг с лодки. За четыре часа — два судака по килограмму. Для речки неплохо. Главное — правильная проводка.'),
(1, 'Котёнок', 'Знакомые отдали котёнка. Маленький, рыжий, пищит постоянно. Барсик пока в шоке. Сидит на шкафу и смотрит сверху вниз с выражением «что это такое и зачем оно здесь».'),
(1, 'Первый снег', 'Выглянул утром в окно — всё белое. Первый снег в этом году. Красиво, но ехать на работу по нечищеным дорогам — удовольствие сомнительное.'),
(1, 'Тренажёрный зал', 'Записался в зал. Тренер составил программу на три дня в неделю. Первая тренировка далась тяжело, но это нормально. Через месяц должно стать легче.'),
(1, 'Поход в горы', 'Поднимались на вершину шесть часов. Ноги гудели, спина болела, но вид сверху того стоил. Облака буквально под ногами. Фотки получились потрясающие.'),
(1, 'Ночная рыбалка', 'Остался на ночную рыбалку. Тишина, звёзды, только поплавок светится в воде. Поймал сома на полтора кило. Ночью они активнее — это факт.'),
(1, 'Барсик у ветеринара', 'Возил Барсика на прививку. Орал так, что вся очередь обернулась. Ветеринар сказал, что кот здоров, просто драматичный. Согласен.'),
(1, 'Гроза', 'Вчера была сильнейшая гроза. Молнии каждые пять секунд, ливень стеной. Отключили электричество на два часа. Сидели при свечах, как в старые времена.'),
(1, 'Велосипед', 'Достал велосипед после зимы. Подкачал колёса, смазал цепь. Проехал двадцать километров по набережной. Ветер в лицо, солнце, свобода.'),
(1, 'Сплав по реке', 'Сплавлялись на байдарках по реке. Пороги небольшие, но адреналин зашкаливает. Один раз чуть не перевернулись. Обязательно поеду ещё.'),
(1, 'Карп на фидер', 'Ловил карпа на фидер. Прикормку мешал сам — кукуруза, пеллетс, ароматизатор. Карп пришёл через час. Два по два кило — отличный результат.'),
(1, 'Кот и новогодняя ёлка', 'Поставили ёлку. Барсик за первые десять минут сбил три шара и попытался залезть на верхушку. Ёлка устояла чудом. Теперь вход в комнату для кота закрыт.'),
(1, 'Бабье лето', 'Конец сентября, а на улице плюс двадцать. Листья жёлтые, солнце тёплое, воздух прозрачный. Самое красивое время года. Гуляли в парке два часа.'),
(1, 'Лыжи', 'Открыл лыжный сезон. Трасса подготовлена отлично. Катался три часа, упал раз пять. Мышцы на следующий день напомнили, что лето я провёл на диване.'),
(1, 'Шашлыки под дождём', 'Запланировали шашлыки — пошёл дождь. Но мы не сдались. Натянули тент, развели мангал. Мясо получилось даже лучше обычного. Или просто голод — лучшая приправа.'),
(1, 'Щука на воблер', 'Щука взяла на воблер прямо у берега. Два кило триста. Боролась минут пять, думал сойдёт. Но подсак не подвёл. Лучший улов за этот месяц.'),
(1, 'Два кота', 'Барсик и рыжий котёнок наконец подружились. Спят вместе, играют, вылизывают друг друга. Умилительное зрелище. Рыжего назвали Компот.'),
(1, 'Туман', 'Утром был такой густой туман, что не видно соседний дом. Ехал на работу со скоростью двадцать. Зато выглядело атмосферно — как в фильме ужасов.'),
(1, 'Бассейн', 'Начал ходить в бассейн два раза в неделю. Плаваю по километру за занятие. Отличная кардионагрузка и разгрузка для спины после сидячей работы.'),
(1, 'Грибы', 'Ходили за грибами после дождей. Набрали два ведра белых и подберёзовиков. Часть пожарили с картошкой, часть засушили. Лес щедрый в этом году.'),
(1, 'Форель на платнике', 'Ездили на платный пруд за форелью. Ловили на пасту и блёсны. Поймал четыре штуки. Одну закоптили прямо на берегу — вкуснотища невероятная.'),
(1, 'Компот разбил вазу', 'Рыжий Компот разбил любимую вазу жены. Причём сделал это с таким невозмутимым видом, как будто ваза сама упала. Коты — мастера невинного взгляда.'),
(1, 'Ледяной дождь', 'Ледяной дождь покрыл всё коркой льда. Деревья красивые, как хрустальные, но ходить невозможно. Три раза чуть не упал по дороге до машины.'),
(1, 'Настольный теннис', 'Поставили на работе стол для пинг-понга. Теперь каждый обед — турнир. Пока занимаю третье место из восьми. Цель — первое к концу месяца.'),
(1, 'Кемпинг', 'Первый раз попробовали кемпинг с палаткой и газовой плитой. Готовили на природе, спали под звёздами. Комаров тьма, но в целом — отличный опыт.'),
(1, 'Окунь на отводной', 'Полосатый клевал как бешеный. За два часа — штук пятнадцать окуней. Все некрупные, грамм по двести, но процесс доставил удовольствие. Отпустил обратно.'),
(1, 'Барсик и коробка', 'Принёс домой коробку от телевизора. Барсик залез внутрь и не вылезал три часа. Смотрел из щели, как из бункера. Коробка теперь его собственность.'),
(1, 'Радуга', 'После дождя увидели двойную радугу. Яркую, от горизонта до горизонта. Все вышли на балконы фотографировать. Маленькие моменты, которые поднимают настроение.'),
(1, 'Йога', 'Попробовал йогу. Думал будет легко — просто растяжка. Оказалось, что я не могу дотянуться до собственных коленей. Тренер сказал, что это нормально. Буду ходить.'),
(1, 'Озеро в горах', 'Дошли до горного озера. Вода бирюзовая, ледяная. Окунулся на секунду — дух захватило. Вокруг сосны и камни. Место, куда хочется вернуться.'),
(1, 'Налим', 'Поймал налима. Первый раз в жизни. Некрасивый, скользкий, но из него получилась отличная уха. Говорят, печень налима — деликатес. Подтверждаю.'),
(1, 'Коты и робот-пылесос', 'Купил робот-пылесос. Барсик шипит на него и убегает. Компот катается сверху, как на танке. Два кота — две стратегии выживания.');
